mapper.select:
SELECT r.id, r.user_id, u.name AS user_name, u.email AS user_email, r.permission_code, p.display_name AS permission_name, r.description, r.status, r.requested_by, ru.name AS requested_by_name, r.decided_by, r.decided_at, r.created_at FROM admin_permission_request r JOIN users u ON u.id = r.user_id LEFT JOIN admin_permission_policy p ON p.permission_code = r.permission_code LEFT JOIN users ru ON ru.id = r.requested_by
AND r.status = #{status}
ORDER BY r.id DESC LIMIT #{limit}
